import{c as e,Q as r,j as a,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"Deep Research Demo for Claude Agent SDK — @trq212","description":"","frontmatter":{"title":"Deep Research Demo for Claude Agent SDK — @trq212","author":"Thariq（@trq212）","date":"2025-11-12T00:00:00.000Z","source":"https://x.com/trq212/status/1988690675542675536","type":"tweet"},"headers":[],"relativePath":"research/tweets/2025-11-12-@trq212-675536.md","filePath":"research/tweets/2025-11-12-@trq212-675536.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2025-11-12-@trq212-675536.md"};function n(d,t,h,l,i,g){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="deep-research-demo-for-claude-agent-sdk-—-trq212" tabindex="-1">Deep Research Demo for Claude Agent SDK — @trq212 <a class="header-anchor" href="#deep-research-demo-for-claude-agent-sdk-—-trq212" aria-label="Permalink to &quot;Deep Research Demo for Claude Agent SDK — @trq212&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/trq212/status/1988690675542675536" target="_blank" rel="noreferrer">https://x.com/trq212/status/1988690675542675536</a><strong>作者</strong>：Thariq（@trq212） <strong>發布日期</strong>：2025-11-12 <strong>收錄日期</strong>：2026-05-16 <strong>類型</strong>：一般推文（thread 入口，含技術說明） <strong>統計</strong>：757 likes · 50 retweets · 1013 bookmarks · 78333 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>We built a Deep Research demo for the Claude Agent SDK!</p><p>It&#39;s one our most requested use cases: spawn multiple AI agents to research a topic in parallel, then synthesize their findings into a report.</p><p>🧵 on how it works:</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>Claude Agent SDK Deep Research demo：多個 AI agent 並行研究同一主題，再彙整報告。Pattern 可移植到任何需要並行研究的 agent 工作流。</p><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><ol><li><strong>Fan-out pattern</strong>：spawn multiple AI agents 並行研究</li><li><strong>Synthesis</strong>：多 agent 結果彙整成單一報告</li><li><strong>最常見 use case 之一</strong>：官方確認這是最多人要求的場景</li><li><em>(thread 細節需至原始推文閱讀)</em></li></ol><h2 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h2><ol><li><strong>有 thread 說明</strong>：🧵 表示有後續技術說明，比單則推文價值更高</li><li><strong>與 subagent-strategy.md 一致</strong>：cc-workspace 已有 fan-out 架構，此 demo 是官方實作參考</li><li><strong>僅 intro</strong>：完整實作細節需至 thread 主體</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>7/10</td><td>Fan-out research pattern 可套用於 cc-workspace researcher agent</td></tr><tr><td>B. 創新性 (20%)</td><td>7/10</td><td>並行多 agent 研究是有效 pattern，官方 demo 增加可信度</td></tr><tr><td>C. 證據品質 (20%)</td><td>4/10</td><td>僅 intro；thread 主體需手動閱讀</td></tr><tr><td>D. 技術深度 (15%)</td><td>5/10</td><td>有 thread 說明但此則僅為入口</td></tr><tr><td>E. 泛化性 (15%)</td><td>8/10</td><td>適用任何需要並行研究的 agent 場景</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.25/10</strong></td><td>7×0.3+7×0.2+4×0.2+5×0.15+8×0.15 = 2.10+1.40+0.80+0.75+1.20</td></tr></tbody></table><p><strong>整合決策</strong>：Agent <strong>理由</strong>：分數 6.25 &gt; 6，核心是多步驟自主研究流程（fan-out → synthesize）；可補充 subagent-strategy.md 的 Researcher agent 設計</p>',18)])])}const u=e(s,[["render",n]]);export{p as __pageData,u as default};
